uv run --with=requests python3 <<'PYTHON'
import os, requests, json

with open('.env') as f:
    for line in f:
        line = line.strip()
        if line and not line.startswith('#') and '=' in line:
            key, _, value = line.partition('=')
            os.environ.setdefault(key.strip(), value.strip())

token = os.environ['VERCEL_TOKEN']
project_id = os.environ['VERCEL_PROJECT_ID']
org_id = os.environ['VERCEL_ORG_ID']

headers = {
    'Authorization': f'Bearer {token}',
    'Content-Type': 'application/json'
}

payload = {
    'name': 'tldr-flask-scraper',
    'project': project_id,
    'gitSource': {
        'type': 'github',
        'ref': 'fix-data-inconsistency',
        'repoId': 1063075532
    }
}

r = requests.post(f'https://api.vercel.com/v13/deployments?teamId={org_id}', headers=headers, json=payload)
result = r.json()

if r.status_code in (200, 201):
    print(f"Preview URL:  https://{result['url']}")
    print(f"Inspector:    {result['inspectorUrl']}")
else:
    print(f"Error {r.status_code}: {json.dumps(result, indent=2)}")
